class Solution:
    def minAbsoluteDifference(self, nums, x):
        n = len(nums)
        best = float('inf')
        for i in range(n):
            for j in range(i + 1, n):
                if j - i >= x:
                    diff = abs(nums[i] - nums[j])
                    if diff < best:
                        best = diff
        return best if best != float('inf') else 0

