import bisect

class Solution:
    def minAbsoluteDifference(self, nums, x):
        n = len(nums)
        lag = max(x, 1)
        window = []
        best = float('inf')
        for j in range(n):
            release = j - lag
            if release >= 0:
                bisect.insort(window, nums[release])
            if window:
                pos = bisect.bisect_left(window, nums[j])
                if pos < len(window):
                    best = min(best, abs(window[pos] - nums[j]))
                if pos > 0:
                    best = min(best, abs(window[pos - 1] - nums[j]))
        return best if best != float('inf') else 0

