var minAbsoluteDifference = function(nums, x) {
    const n = nums.length;
    const lag = Math.max(x, 1);
    const window = [];

    function bisectLeft(arr, value) {
        let lo = 0, hi = arr.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (arr[mid] < value) lo = mid + 1;
            else hi = mid;
        }
        return lo;
    }

    let best = Infinity;
    for (let j = 0; j < n; j++) {
        const release = j - lag;
        if (release >= 0) {
            const insertAt = bisectLeft(window, nums[release]);
            window.splice(insertAt, 0, nums[release]);
        }
        if (window.length > 0) {
            const pos = bisectLeft(window, nums[j]);
            if (pos < window.length) best = Math.min(best, Math.abs(window[pos] - nums[j]));
            if (pos > 0) best = Math.min(best, Math.abs(window[pos - 1] - nums[j]));
        }
    }
    return best === Infinity ? 0 : best;
};
